const KEY = 'ticks';

export function radial_ticks_position(data) {
    const position = this.helpers.position;

    //* define variables here
    const { commonOption } = this,
        {  tickConstants, transform, position: pos_scale } = commonOption,
        { x, y, w } = tickConstants;

    position[KEY] = {
        attrs_key: { x, y, w },
        end: function end(d, encode) {
            return transform(pos_scale(d));
        }
    }

    //* also add for gridline here
    const KEY2 = 'gridline';
    position[KEY2] = {};
}

